decimal sumRFemaleStarted = 0;
decimal sumCounterTotal = 0;
decimal sumDOA = 0;
decimal sumRFemaleCatchLoss = 0;
decimal sumScaleWeight = 0;
decimal sumDeplation = 0;
decimal sumTotalWeightWithLoss = 0;
decimal sumBroScaleWeight = 0;
decimal sumDeviation = 0;
decimal sumCulls = 0;
private void xrTableCell20_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get the required field values
    decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);
    decimal counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal") ?? 0);
    decimal doa = Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
    decimal rfFemaleCatchLoss = Convert.ToDecimal(GetCurrentColumnValue("rf_FemaleCatchLoss") ?? 0);

    if (rfFemaleStarted != 0)
    {
        // Calculate total depletion (CounterTotal + DOA + rf_FemaleCatchLoss)
        decimal totalDepletion = counterTotal + doa + rfFemaleCatchLoss;

        // Calculate percentage
        decimal result = (totalDepletion / rfFemaleStarted) * 100.0m;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }
}


private void xrTableCell12_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

    // Get the required field values
    decimal counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal") ?? 0);
    decimal doa = Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
    decimal scaleWeight = Convert.ToDecimal(GetCurrentColumnValue("ScaleWeight") ?? 0);

    // Calculate total birds (CounterTotal + DOA)
    decimal totalBirds = counterTotal + doa;

    if (totalBirds != 0)
    {
        // Calculate average weight per bird
        decimal result = scaleWeight / totalBirds;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell50_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

    // Get the required field values
    decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);
    decimal deplation = Convert.ToDecimal(GetCurrentColumnValue("DEPLATION") ?? 0);

    if (rfFemaleStarted != 0)
    {
        // Calculate survival percentage
        decimal result = ((rfFemaleStarted - deplation) / rfFemaleStarted) * 100;
        cell.Text = result.ToString("N2") ;
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell36_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            XRTableCell cell = sender as XRTableCell;

        // Get required field values
        decimal rfFemaleCatchLoss = Convert.ToDecimal(GetCurrentColumnValue("rf_FemaleCatchLoss") ?? 0);
        decimal counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal") ?? 0);
        decimal doa = Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
        decimal scaleWeight = Convert.ToDecimal(GetCurrentColumnValue("ScaleWeight") ?? 0);

        // Calculate {@Pt_AvgLive} - average live weight
        decimal ptAvgLive = 0;
        decimal totalBirds = counterTotal + doa;

        if (totalBirds != 0)
        {
            ptAvgLive = scaleWeight / totalBirds;
        }

        // Calculate total weight with catch loss
        decimal result = (rfFemaleCatchLoss * ptAvgLive) + scaleWeight;

        cell.Text = result.ToString("N2") ;
}

private void xrTableCell55_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            XRTableCell cell = sender as XRTableCell;

        // Get all required field values
        decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);
        decimal deplation = Convert.ToDecimal(GetCurrentColumnValue("DEPLATION") ?? 0);
        decimal rfFemaleCatchLoss = Convert.ToDecimal(GetCurrentColumnValue("rf_FemaleCatchLoss") ?? 0);
        decimal counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal") ?? 0);
        decimal doa = Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
        decimal scaleWeight = Convert.ToDecimal(GetCurrentColumnValue("ScaleWeight") ?? 0);
        // Calculate {@Pt_AvgLive} - average live weight
        decimal ptAvgLive = 0;
        decimal totalBirds = counterTotal + doa;
        if (totalBirds != 0)
        {
            ptAvgLive = scaleWeight / totalBirds;
        }

        // Calculate {@Bro_ScaleWeight} - total weight including catch loss
        decimal broScaleWeight = (rfFemaleCatchLoss * ptAvgLive) + scaleWeight;

        // Calculate denominator (rf_Female_Started - DEPLATION)
        decimal denominator = rfFemaleStarted - deplation;

        if (denominator != 0)
        {
            // Calculate final average weight
            decimal result = broScaleWeight / denominator;
            cell.Text = result.ToString("N2") ;
        }
        else
        {
            cell.Text = "0.00";
        }
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            sumRFemaleStarted += Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);
        sumCounterTotal += Convert.ToDecimal(GetCurrentColumnValue("CounterTotal") ?? 0);
        sumDOA += Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
        sumRFemaleCatchLoss += Convert.ToDecimal(GetCurrentColumnValue("rf_FemaleCatchLoss") ?? 0);
        sumScaleWeight += Convert.ToDecimal(GetCurrentColumnValue("ScaleWeight") ?? 0);
        sumDeplation += Convert.ToDecimal(GetCurrentColumnValue("DEPLATION") ?? 0);
        sumDeviation += Convert.ToDecimal(GetCurrentColumnValue("Dev") ?? 0); // {@Deviation} is the Dev field
        sumCulls += Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);
        sumDOA += Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);
        // Calculate {@Pt_AvgLive} for this row
        decimal ptAvgLive = 0;
        decimal totalBirds = sumCounterTotal + sumDOA ;
        if (totalBirds != 0)
        {
            ptAvgLive = sumScaleWeight / totalBirds;
        }

        // Calculate total weight with loss for this row
        decimal rowTotalWeightWithLoss = (sumRFemaleCatchLoss * ptAvgLive) + sumScaleWeight ;

        // Add to running total
        sumTotalWeightWithLoss += rowTotalWeightWithLoss;

        decimal broScaleWeight = rowTotalWeightWithLoss ;
        sumBroScaleWeight += broScaleWeight;

}

